/**
 * PR management helpers for the changelog-generation workflow.
 *
 * Extracted from inline `actions/github-script` blocks so the logic can be
 * unit-tested independently of the GitHub Actions runner.
 *
 * Two functions handle the two distinct modes:
 *   - manageUnreleasedPR  — singleton `generated-changelog` → `main` PR
 *   - refreshReleasePR    — update the prep-release-* PR body with metadata
 */

const NO_CHANGELOG_LABEL = 'no-changelog';

function warn(core, message) {
  if (core && typeof core.warning === 'function') {
    core.warning(message);
  }
}

/**
 * Ensure the `no-changelog` label is applied to a PR.
 *
 * Labeling is best-effort: if the primary PR create/update already succeeded,
 * a subsequent labeling failure should not fail the whole workflow.
 *
 * @param {{ github: object, core?: object, owner: string, repo: string, issue_number: number }} opts
 * @returns {Promise<void>}
 */
async function addNoChangelogLabel({ github, core, owner, repo, issue_number }) {
  try {
    await github.rest.issues.addLabels({
      owner,
      repo,
      issue_number,
      labels: [NO_CHANGELOG_LABEL],
    });
  } catch (err) {
    warn(
      core,
      `Failed to apply ${NO_CHANGELOG_LABEL} label to PR #${issue_number}: ${err.message || String(err)}`
    );
  }
}

/**
 * Build the PR body for the generated-changelog PR (unreleased mode).
 *
 * @param {{ compareRange: string }} opts
 * @returns {string}
 */
function buildUnreleasedPRBody({ compareRange }) {
  const today = new Date().toISOString().split('T')[0];
  return [
    `**Generated:** ${today}`,
    `**Compare range:** \`${compareRange}\``,
    '',
    '> This PR is auto-generated by the changelog-generation workflow.',
    '> Re-runs will force-push this branch and overwrite any manual edits.',
    '> Do not make manual edits to the `generated-changelog` branch.',
  ].join('\n');
}

/**
 * Build the PR body for the release prep PR (release mode).
 *
 * @param {{ targetVersion: string, compareRange: string }} opts
 * @returns {string}
 */
function buildReleasePRBody({ targetVersion, compareRange }) {
  const today = new Date().toISOString().split('T')[0];
  return [
    `**Generated:** ${today}`,
    `**Version:** \`${targetVersion}\``,
    `**Compare range:** \`${compareRange}\``,
    '',
    '> This PR body was last refreshed by the changelog-generation workflow.',
  ].join('\n');
}

/**
 * Manage the singleton `generated-changelog` PR (unreleased mode).
 *
 * Looks up any existing open PR from `generated-changelog` → `main`.
 * If found, updates its body and returns action='updated'.
 * If not found, creates a new PR and returns action='created'.
 *
 * @param {{ github: object, core?: object, owner: string, repo: string, compareRange: string }} opts
 * @returns {Promise<{ prAction: string, prNumber: number, prUrl: string }>}
 */
async function manageUnreleasedPR({ github, core, owner, repo, compareRange }) {
  const prBody = buildUnreleasedPRBody({ compareRange });

  const { data: existingPRs } = await github.rest.pulls.list({
    owner,
    repo,
    state: 'open',
    head: `${owner}:generated-changelog`,
    base: 'main',
  });

  if (existingPRs.length > 0) {
    const existingPR = existingPRs[0];
    await github.rest.pulls.update({
      owner,
      repo,
      pull_number: existingPR.number,
      body: prBody,
    });
    await addNoChangelogLabel({
      github,
      owner,
      repo,
      core,
      issue_number: existingPR.number,
    });
    return {
      prAction: 'updated',
      prNumber: existingPR.number,
      prUrl: existingPR.html_url,
    };
  }

  const { data: newPR } = await github.rest.pulls.create({
    owner,
    repo,
    title: 'chore: update CHANGELOG.md [Unreleased] section',
    body: prBody,
    head: 'generated-changelog',
    base: 'main',
  });
  await addNoChangelogLabel({
    github,
    owner,
    repo,
    core,
    issue_number: newPR.number,
  });
  return {
    prAction: 'created',
    prNumber: newPR.number,
    prUrl: newPR.html_url,
  };
}

/**
 * Find the open release prep PR for a version (`prep-release-<semver>` → `main`).
 *
 * @param {{ github: object, owner: string, repo: string, targetVersion: string }} opts
 * @returns {Promise<number|null>}
 */
async function findOpenReleasePrepPRNumber({ github, owner, repo, targetVersion }) {
  if (!targetVersion) {
    return null;
  }
  const head = `prep-release-${targetVersion}`;
  const { data: prs } = await github.rest.pulls.list({
    owner,
    repo,
    state: 'open',
    head: `${owner}:${head}`,
    base: 'main',
  });
  return prs.length > 0 ? prs[0].number : null;
}

/**
 * Refresh the release prep PR body with generated metadata.
 *
 * When `prNumber` is absent (e.g. workflow_dispatch), looks up an open PR with
 * head `prep-release-<targetVersion>` and base `main`.
 *
 * @param {{ github: object, core: object, owner: string, repo: string, prNumber: number|null|undefined, compareRange: string, targetVersion: string }} opts
 * @returns {Promise<void>}
 */
async function refreshReleasePR({ github, core, owner, repo, prNumber, compareRange, targetVersion }) {
  let num = prNumber ?? null;
  if (!num) {
    num = await findOpenReleasePrepPRNumber({ github, owner, repo, targetVersion });
  }
  if (!num) {
    core.warning(
      'Could not resolve a release prep PR to refresh (no PR number and no open PR for ' +
        `prep-release-${targetVersion || '<version>'} → main); skipping PR body update`
    );
    return;
  }

  const prBody = buildReleasePRBody({ targetVersion, compareRange });

  core.info(`Refreshing release PR #${num} metadata`);
  await github.rest.pulls.update({
    owner,
    repo,
    pull_number: num,
    body: prBody,
  });
  await addNoChangelogLabel({
    github,
    core,
    owner,
    repo,
    issue_number: num,
  });
  core.info(`Release PR #${num} metadata refreshed`);
}

if (typeof module !== 'undefined') {
  module.exports = {
    buildUnreleasedPRBody,
    buildReleasePRBody,
    manageUnreleasedPR,
    findOpenReleasePrepPRNumber,
    refreshReleasePR,
  };
}
